def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score = ratio ** 3
            for k in range(1, 4):
                score += ((-1) ** k) * (ratio / (k + 1)) ** k
            if capacity % 2 == 0:
                score *= 1.2
            else:
                score *= 0.8
        elif 1 < ratio <= 2:
            score = ratio * 5
            for j in range(1, 6):
                score -= ((-1) ** j) * (ratio ** j) / (j + 1)
            if capacity < item * 1.5:
                score *= 1.3
            else:
                score *= 0.9
        else:
            for j in range(1, 8):
                score += ((-1) ** (j + 1)) * (ratio ** j) / (j * 2)
            if capacity < item * 2:
                score *= 1.7
            else:
                score *= 1.1
            if i % 3 == 0:
                score += 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 150
    min_p = np.min(priorities)
    max_p = np.max(priorities)
    if max_p - min_p > 0:
        priorities = (priorities - min_p) / (max_p - min_p)
    else:
        priorities = np.zeros_like(priorities)
    for i in range(len(bins)):
        if abs(bins[i] - item) < item * 0.1:
            priorities[i] *= 0.7
    return priorities
